const xmlText = $input.first().json.data || $input.first().json.body || String($input.first().json);

function parseCalendarXML(xml) {
  const events = [];
  const rowMatches = xml.match(/<row[^>]*>[\s\S]*?<\/row>/gi) || [];

  for (const rowXml of rowMatches) {
    const getAttr = (attr) => {
      const match = rowXml.match(new RegExp(attr + '="([^"]*)"'));
      return match ? match[1].trim() : '';
    };
    const getTag = (tag) => {
      const match = rowXml.match(new RegExp('<' + tag + '>([\\s\\S]*?)<\\/' + tag + '>', 'i'));
      return match ? match[1].trim() : '';
    };

    const title = getAttr('title') || getTag('title') || getTag('name');
    const time = getAttr('time') || getTag('time');
    const impact = getAttr('impact') || getTag('impact');
    const forecast = getAttr('forecast') || getTag('forecast');
    const previous = getAttr('previous') || getTag('previous');
    const actual = getAttr('actual') || getTag('actual');
    const currency = getAttr('currency') || getTag('currency') || 'USD';

    if (title) {
      events.push({
        time: time || 'TBA',
        title: title,
        currency: currency,
        impact: impact === '3' ? 'HIGH' : impact === '2' ? 'MEDIUM' : impact || 'MEDIUM',
        forecast: forecast || '-',
        previous: previous || '-',
        actual: actual || '-'
      });
    }
  }

  if (events.length === 0) {
    const eventMatches = xml.match(/<event[^>]*>[\s\S]*?<\/event>/gi) || [];
    for (const eventXml of eventMatches) {
      const getTag = (tag) => {
        const match = eventXml.match(new RegExp('<' + tag + '>([\\s\\S]*?)<\\/' + tag + '>', 'i'));
        return match ? match[1].trim() : '';
      };
      events.push({
        time: getTag('time') || 'TBA',
        title: getTag('title') || getTag('name') || 'Unknown',
        impact: getTag('impact') === '3' ? 'HIGH' : getTag('impact') === '2' ? 'MEDIUM' : 'LOW',
        forecast: getTag('forecast') || '-',
        previous: getTag('previous') || '-'
      });
    }
  }

  return events;
}

let parsedEvents = [];
try {
  parsedEvents = parseCalendarXML(xmlText);
} catch (e) {
  console.log('XML Parse error:', e.message);
}

const impactOrder = { 'HIGH': 0, 'MEDIUM': 1, 'LOW': 2 };
parsedEvents.sort((a, b) => (impactOrder[a.impact] || 2) - (impactOrder[b.impact] || 2));

return {
  json: {
    economicCalendar: parsedEvents.slice(0, 20)
  }
};

const input = $input.first().json;
const calendarData = input.calendar;

// ==================== HELPER FUNCTIONS ====================

function calculateEMA(closes, period) {
  if (closes.length < period) return null;
  const multiplier = 2 / (period + 1);
  let ema = closes.slice(0, period).reduce((a, b) => a + b, 0) / period;
  for (let i = period; i < closes.length; i++) {
    ema = (closes[i] - ema) * multiplier + ema;
  }
  return ema;
}

function calculateEMAArray(closes, period) {
  if (closes.length < period) return [];
  const multiplier = 2 / (period + 1);
  let ema = closes.slice(0, period).reduce((a, b) => a + b, 0) / period;
  const emas = new Array(period - 1).fill(null);
  emas.push(ema);
  for (let i = period; i < closes.length; i++) {
    ema = (closes[i] - ema) * multiplier + ema;
    emas.push(ema);
  }
  return emas;
}

function aggregateBars(bars5min, factor) {
  const aggregated = [];
  for (let i = 0; i < bars5min.length; i += factor) {
    const chunk = bars5min.slice(i, i + factor);
    if (chunk.length === factor) {
      aggregated.push({
        datetime: chunk[0].datetime,
        open: parseFloat(chunk[0].open),
        high: Math.max(...chunk.map(b => parseFloat(b.high))),
        low: Math.min(...chunk.map(b => parseFloat(b.low))),
        close: parseFloat(chunk[chunk.length - 1].close),
        volume: chunk.reduce((sum, b) => sum + (parseInt(b.volume) || 0), 0)
      });
    }
  }
  return aggregated;
}

function findSwingPoints(bars) {
  const swingHighs = [];
  const swingLows = [];
  for (let i = 1; i < bars.length - 1; i++) {
    const prev = bars[i - 1];
    const curr = bars[i];
    const next = bars[i + 1];
    if (parseFloat(curr.high) > parseFloat(prev.high) && parseFloat(curr.high) > parseFloat(next.high)) {
      swingHighs.push({ price: parseFloat(curr.high), time: curr.datetime, index: i });
    }
    if (parseFloat(curr.low) < parseFloat(prev.low) && parseFloat(curr.low) < parseFloat(next.low)) {
      swingLows.push({ price: parseFloat(curr.low), time: curr.datetime, index: i });
    }
  }
  return { swingHighs, swingLows };
}

function detectConsolidation(bars, lookback) {
  lookback = lookback || 10;
  if (bars.length < lookback + 1) return { isConsolidating: false, ratio: 1 };
  const trueRanges = [];
  for (let i = 1; i < bars.length; i++) {
    const high = parseFloat(bars[i].high);
    const low = parseFloat(bars[i].low);
    const prevClose = parseFloat(bars[i - 1].close);
    const tr = Math.max(high - low, Math.abs(high - prevClose), Math.abs(low - prevClose));
    trueRanges.push(tr);
  }
  const avgTR = trueRanges.reduce((a, b) => a + b, 0) / trueRanges.length;
  const recentTRs = trueRanges.slice(-lookback);
  const recentAvgTR = recentTRs.reduce((a, b) => a + b, 0) / recentTRs.length;
  const ratio = recentAvgTR / avgTR;
  return { isConsolidating: ratio < 0.6, ratio: ratio.toFixed(2) };
}

// Determine session based on timestamp hour
// isUTC: true for forex/crypto (XAU, XAG, BTC), false for CME futures (ES, NQ)
function getSession(datetime, isUTC) {
  const parts = datetime.split(' ');
  if (parts.length < 2) return 'unknown';
  const hour = parseInt(parts[1].split(':')[0]);
  if (isUTC) {
    // UTC timestamps: Tokyo ~22:00-07:00, London ~07:00-13:00, Pre-NY ~13:00+
    if (hour >= 22 || hour < 7) return 'tokyo';
    if (hour >= 7 && hour < 13) return 'london';
    return 'preNY';
  } else {
    // ET timestamps: Tokyo ~18:00-02:00, London ~02:00-08:00, Pre-NY ~08:00+
    if (hour >= 18 || hour < 2) return 'tokyo';
    if (hour >= 2 && hour < 8) return 'london';
    return 'preNY';
  }
}

// Calculate EMA slope direction
function emaSlope(closes, period, lookback) {
  lookback = lookback || 5;
  if (closes.length < period + lookback) return 'N/A';
  const emas = calculateEMAArray(closes, period);
  const recent = emas.slice(-lookback).filter(function(v) { return v !== null; });
  if (recent.length < 2) return 'N/A';
  const diff = recent[recent.length - 1] - recent[0];
  const avgPrice = recent.reduce(function(a, b) { return a + b; }, 0) / recent.length;
  const pctChange = (diff / avgPrice) * 100;
  if (pctChange > 0.02) return 'RISING';
  if (pctChange < -0.02) return 'FALLING';
  return 'FLAT';
}

// ==================== MAIN ANALYSIS FUNCTION ====================

function analyzeInstrument(data5min, data60min, dailyData, instrumentName) {
  if (!data5min || !data5min.values || data5min.values.length === 0) {
    return { instrument: instrumentName, error: 'No data available', bias: 'UNKNOWN' };
  }

  // Determine if timestamps are UTC or ET
  var isUTC = instrumentName.toLowerCase().indexOf('gold') >= 0 ||
              instrumentName.toLowerCase().indexOf('silver') >= 0 ||
              instrumentName.toLowerCase().indexOf('btc') >= 0;

  // TwelveData returns newest first, reverse for chronological
  var bars5min = data5min.values.slice().reverse();
  var bars60min = data60min && data60min.values ? data60min.values.slice().reverse() : [];

  // Aggregate to 10min and 15min
  var bars10min = aggregateBars(bars5min, 2);
  var bars15min = aggregateBars(bars5min, 3);

  // Calculate EMAs
  var closes5min = bars5min.map(function(b) { return parseFloat(b.close); });
  var closes10min = bars10min.map(function(b) { return b.close; });
  var closes15min = bars15min.map(function(b) { return b.close; });
  var closes60min = bars60min.map(function(b) { return parseFloat(b.close); });

  var ema21_10min = calculateEMA(closes10min, 21);
  var ema21_15min = calculateEMA(closes15min, 21);
  var ema21_60min = calculateEMA(closes60min, 21);

  // EMA slopes
  var slope10 = emaSlope(closes10min, 21);
  var slope15 = emaSlope(closes15min, 21);
  var slope60 = emaSlope(closes60min, 21);

  // Decimal places
  var isBTC = instrumentName.toLowerCase().indexOf('btc') >= 0;
  var isSilver = instrumentName.toLowerCase().indexOf('silver') >= 0;
  var isES = instrumentName.toLowerCase().indexOf('es') >= 0 || instrumentName.toLowerCase().indexOf('s&p') >= 0;
  var isNQ = instrumentName.toLowerCase().indexOf('nq') >= 0 || instrumentName.toLowerCase().indexOf('nasdaq') >= 0;
  var decimals = isBTC ? 0 : (isSilver ? 3 : 2);

  // ===== SESSION ANALYSIS USING REAL HOURS =====
  var tokyoBars = bars5min.filter(function(b) { return getSession(b.datetime, isUTC) === 'tokyo'; });
  var londonBars = bars5min.filter(function(b) { return getSession(b.datetime, isUTC) === 'london'; });
  var preNYBars = bars5min.filter(function(b) { return getSession(b.datetime, isUTC) === 'preNY'; });

  function sessionStats(bars, name) {
    if (!bars || bars.length === 0) return { session: name, high: 'N/A', low: 'N/A', open: 'N/A', close: 'N/A', bias: 'NO DATA', range: 'N/A', barCount: 0 };
    var highs = bars.map(function(b) { return parseFloat(b.high); });
    var lows = bars.map(function(b) { return parseFloat(b.low); });
    var open = parseFloat(bars[0].open);
    var close = parseFloat(bars[bars.length - 1].close);
    var high = Math.max.apply(null, highs);
    var low = Math.min.apply(null, lows);
    return {
      session: name,
      high: high.toFixed(decimals),
      low: low.toFixed(decimals),
      open: open.toFixed(decimals),
      close: close.toFixed(decimals),
      range: (high - low).toFixed(decimals),
      bias: close > open ? 'BULLISH' : close < open ? 'BEARISH' : 'NEUTRAL',
      barCount: bars.length
    };
  }

  var tokyoStats = sessionStats(tokyoBars, 'Tokyo');
  var londonStats = sessionStats(londonBars, 'London');
  var preNYStats = sessionStats(preNYBars, 'Pre-NY');

  // Overall stats
  var allHighs = bars5min.map(function(b) { return parseFloat(b.high); });
  var allLows = bars5min.map(function(b) { return parseFloat(b.low); });
  var sessionHigh = Math.max.apply(null, allHighs);
  var sessionLow = Math.min.apply(null, allLows);
  var sessionOpen = parseFloat(bars5min[0].open);
  var sessionClose = parseFloat(bars5min[bars5min.length - 1].close);
  var priceChange = sessionClose - sessionOpen;
  var percentChange = ((priceChange / sessionOpen) * 100);

  // ===== PREVIOUS DAY LEVELS (PDH/PDL/PDC) =====
  var pdh = 'N/A', pdl = 'N/A', pdc = 'N/A';
  var priceVsPDH = 'N/A', priceVsPDL = 'N/A', priceVsPDC = 'N/A';
  var gapFromPDC = 'N/A';

  if (dailyData && dailyData.values && dailyData.values.length >= 2) {
    var prevDay = dailyData.values[1]; // values[0] = today partial, values[1] = prev day
    pdh = parseFloat(prevDay.high).toFixed(decimals);
    pdl = parseFloat(prevDay.low).toFixed(decimals);
    pdc = parseFloat(prevDay.close).toFixed(decimals);

    priceVsPDH = ((sessionClose - parseFloat(prevDay.high)) / parseFloat(prevDay.high) * 100).toFixed(3) + '%';
    priceVsPDL = ((sessionClose - parseFloat(prevDay.low)) / parseFloat(prevDay.low) * 100).toFixed(3) + '%';
    priceVsPDC = ((sessionClose - parseFloat(prevDay.close)) / parseFloat(prevDay.close) * 100).toFixed(3) + '%';

    var gap = sessionOpen - parseFloat(prevDay.close);
    gapFromPDC = gap.toFixed(decimals) + ' (' + ((gap / parseFloat(prevDay.close)) * 100).toFixed(3) + '%)';
  }

  // Swing points from 15min bars
  var swingPoints = findSwingPoints(bars15min);

  // Consolidation detection
  var consolidation = detectConsolidation(bars15min);

  // Price vs EMAs
  var currentPrice = sessionClose;
  var priceVsEMA10 = ema21_10min ? ((currentPrice - ema21_10min) / ema21_10min * 100).toFixed(3) : null;
  var priceVsEMA15 = ema21_15min ? ((currentPrice - ema21_15min) / ema21_15min * 100).toFixed(3) : null;
  var priceVsEMA60 = ema21_60min ? ((currentPrice - ema21_60min) / ema21_60min * 100).toFixed(3) : null;

  // EMA proximity alert (within 0.1% of 15min EMA)
  var emaProximity15 = priceVsEMA15 ? Math.abs(parseFloat(priceVsEMA15)) < 0.1 : false;

  return {
    instrument: instrumentName,
    symbol: data5min.meta ? data5min.meta.symbol : instrumentName,
    currentPrice: currentPrice.toFixed(decimals),
    overall: {
      open: sessionOpen.toFixed(decimals),
      high: sessionHigh.toFixed(decimals),
      low: sessionLow.toFixed(decimals),
      close: sessionClose.toFixed(decimals),
      range: (sessionHigh - sessionLow).toFixed(decimals),
      change: priceChange.toFixed(decimals),
      percentChange: percentChange.toFixed(3)
    },
    previousDay: {
      high: pdh,
      low: pdl,
      close: pdc,
      priceVsPDH: priceVsPDH,
      priceVsPDL: priceVsPDL,
      priceVsPDC: priceVsPDC,
      gapFromPDC: gapFromPDC
    },
    tokyo: tokyoStats,
    london: londonStats,
    preNY: preNYStats,
    emaLevels: {
      ema21_10min: ema21_10min ? ema21_10min.toFixed(decimals) : 'N/A',
      ema21_15min: ema21_15min ? ema21_15min.toFixed(decimals) : 'N/A',
      ema21_60min: ema21_60min ? ema21_60min.toFixed(decimals) : 'N/A',
      slope10min: slope10,
      slope15min: slope15,
      slope60min: slope60,
      priceVsEMA10: priceVsEMA10 ? priceVsEMA10 + '%' : 'N/A',
      priceVsEMA15: priceVsEMA15 ? priceVsEMA15 + '%' : 'N/A',
      priceVsEMA60: priceVsEMA60 ? priceVsEMA60 + '%' : 'N/A',
      emaProximityAlert15: emaProximity15 ? 'PRICE NEAR 15min 21 EMA - WATCH FOR RETEST' : 'Price away from 15min EMA'
    },
    swingPoints: {
      recentHighs: swingPoints.swingHighs.slice(-3).map(function(s) { return { price: s.price.toFixed(decimals), time: s.time }; }),
      recentLows: swingPoints.swingLows.slice(-3).map(function(s) { return { price: s.price.toFixed(decimals), time: s.time }; })
    },
    consolidation: {
      is15minConsolidating: consolidation.isConsolidating,
      atrRatio: consolidation.ratio,
      warning: consolidation.isConsolidating ? 'CAUTION: 15min consolidating - AVOID EMA retest setups' : 'OK: Normal volatility'
    },
    bias: priceChange > 0 ? 'BULLISH' : priceChange < 0 ? 'BEARISH' : 'NEUTRAL',
    barsAnalyzed: {
      '5min': bars5min.length, '10min': bars10min.length, '15min': bars15min.length,
      '60min': bars60min.length, 'tokyo': tokyoBars.length, 'london': londonBars.length, 'preNY': preNYBars.length
    }
  };
}

// ==================== ANALYZE ALL INSTRUMENTS ====================

var gcAnalysis = analyzeInstrument(input.gc5min, input.gc60min, input.gcDaily, 'Gold (GC)');
var nqAnalysis = analyzeInstrument(input.nq5min, input.nq60min, input.nqDaily, 'Nasdaq (NQ)');
var esAnalysis = analyzeInstrument(input.es5min, input.es60min, input.esDaily, 'S&P 500 (ES)');
var silverAnalysis = analyzeInstrument(input.silver5min, input.silver60min, input.silverDaily, 'Silver (SI)');
var btcAnalysis = analyzeInstrument(input.btc5min, input.btc60min, input.btcDaily, 'Bitcoin (BTC)');

// Calendar events (all impact levels, sorted high first)
var allEvents = calendarData && calendarData.economicCalendar ? calendarData.economicCalendar : [];
var impactEvents = allEvents.map(function(event) {
  return {
    time: event.time || 'TBA',
    event: event.title || event.event || event.name || 'Unknown Event',
    forecast: event.forecast || '-',
    previous: event.previous || '-',
    actual: event.actual || '-',
    impact: event.impact || 'MEDIUM'
  };
}).slice(0, 15);

return {
  json: {
    timestamp: new Date().toISOString(),
    gc: gcAnalysis,
    nq: nqAnalysis,
    es: esAnalysis,
    silver: silverAnalysis,
    btc: btcAnalysis,
    impactNews: impactEvents,
    totalNewsEvents: allEvents.length
  }
};

// Encode chart images to base64
const gcChart = $('Fetch GC Chart Image').first();
const nqChart = $('Fetch NQ Chart Image').first();
const esChart = $('Fetch ES Chart Image').first();
const silverChart = $('Fetch Silver Chart Image').first();
const btcChart = $('Fetch BTC Chart Image').first();

function getBase64(item) {
  try {
    if (item.binary && item.binary.data) {
      return item.binary.data.data; // Already base64 in n8n
    }
    return null;
  } catch (e) {
    return null;
  }
}

return {
  json: {
    gcChartBase64: getBase64(gcChart),
    nqChartBase64: getBase64(nqChart),
    esChartBase64: getBase64(esChart),
    silverChartBase64: getBase64(silverChart),
    btcChartBase64: getBase64(btcChart)
  }
};
